@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted text-uppercase small fw-bold">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                    <span class="me-2">@section.Icon</span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];
}

.settings-sidebar {
    min-width: 220px;
    border-right: 1px solid var(--bs-border-color);
    padding: 1rem 0;
    background: var(--bs-body-bg);
}

.settings-sidebar .nav-link {
    color: var(--bs-body-color);
    border-radius: 0;
    padding: 0.6rem 1.2rem;
    transition: background-color 0.15s;
}

.settings-sidebar .nav-link:hover {
    background-color: var(--bs-tertiary-bg);
}

.settings-sidebar .nav-link.active {
    background-color: var(--bs-primary);
    color: #fff;
    font-weight: 600;
}

@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings
@using sv_e6d10935b0844757af832ef3520809a2.Services

<div class="p-4">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_profile is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="row mb-4">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="avatar-preview mb-2">
                <img src="@_profile.AvatarUrl" alt="Avatar" class="rounded-circle img-fluid"
                     style="width:120px;height:120px;object-fit:cover;" />
            </div>
            <small class="text-muted text-break">@_profile.AvatarUrl</small>
        </div>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Profile saved successfully!
            <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
        </div>
    }

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback OnSaved { get; set; }

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _saving;
    private bool _showSuccess;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields();
    }

    private void PopulateFields()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _bio = _profile.Bio;
    }

    private async Task SaveAsync()
    {
        if (_profile is null) return;
        _saving = true;
        var updated = _profile with { DisplayName = _displayName, Email = _email, Bio = _bio };
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _saving = false;
        _showSuccess = true;
        await OnSaved.InvokeAsync();
    }

    private void Discard()
    {
        PopulateFields();
        _showSuccess = false;
    }
}

@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings
@using sv_e6d10935b0844757af832ef3520809a2.Services

<div class="p-4">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_prefs is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@_emailNotifications" @onchange="e => _emailNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@_pushNotifications" @onchange="e => _pushNotifications = (bool)e.Value!" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@_weeklyDigest" @onchange="e => _weeklyDigest = (bool)e.Value!" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h5 class="mb-3">Muted Channels</h5>
    <div class="mb-4">
        @foreach (var channel in _allChannels)
        {
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@_mutedChannels.Contains(channel)"
                       @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Preferences saved!
            <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback OnSaved { get; set; }

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private bool _saving;
    private bool _showSuccess;

    private static readonly string[] _allChannels = ["general", "announcements", "marketing", "events", "support"];

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _prefs = updated;
        _saving = false;
        _showSuccess = true;
        await OnSaved.InvokeAsync();
    }
}

@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => _expanded = !_expanded">
        <strong>Change Password</strong>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (_errorMessage is not null)
            {
                <div class="alert alert-danger py-2">@_errorMessage</div>
            }
            @if (_successMessage is not null)
            {
                <div class="alert alert-success py-2">@_successMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_updating">
                @if (_updating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _errorMessage;
    private string? _successMessage;
    private bool _updating;

    private async Task UpdatePasswordAsync()
    {
        _errorMessage = null;
        _successMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _errorMessage = "All fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _errorMessage = "New passwords do not match.";
            return;
        }

        _updating = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _successMessage = "Password updated successfully.";
            _currentPassword = _newPassword = _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _updating = false;
        }
    }
}

@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings
@using sv_e6d10935b0844757af832ef3520809a2.Services

<div class="table-responsive">
    <table class="table table-hover align-middle">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id == CurrentSessionId)
                        {
                            <span class="badge bg-success">Current</span>
                        }
                        else if (_confirmingId == session.Id)
                        {
                            <div class="d-flex gap-1">
                                <button class="btn btn-danger btn-sm" @onclick="() => ConfirmRevokeAsync(session.Id)">
                                    Confirm
                                </button>
                                <button class="btn btn-outline-secondary btn-sm" @onclick="CancelConfirm">
                                    Cancel
                                </button>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-danger btn-sm"
                                    @onclick="() => _confirmingId = session.Id">
                                Revoke
                            </button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingId;

    private void CancelConfirm() => _confirmingId = null;

    private async Task ConfirmRevokeAsync(string sessionId)
    {
        _confirmingId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

