{"file_text": "@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings
@using sv_e6d10935b0844757af832ef3520809a2.Services

<div class="p-4">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_profile is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="row mb-4">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="avatar-preview mb-2">
                <img src="@_profile.AvatarUrl" alt="Avatar" class="rounded-circle img-fluid"
                     style="width:120px;height:120px;object-fit:cover;" />
            </div>
            <small class="text-muted text-break">@_profile.AvatarUrl</small>
        </div>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            Profile saved successfully!
            <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
        </div>
    }

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback OnSaved { get; set; }

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _saving;
    private bool _showSuccess;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields();
    }

    private void PopulateFields()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _bio = _profile.Bio;
    }

    private async Task SaveAsync()
    {
        if (_profile is null) return;
        _saving = true;
        var updated = _profile with { DisplayName = _displayName, Email = _email, Bio = _bio };
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _saving = false;
        _showSuccess = true;
        await OnSaved.InvokeAsync();
    }

    private void Discard()
    {
        PopulateFields();
        _showSuccess = false;
    }
}
