@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings
@using sv_e6d10935b0844757af832ef3520809a2.Services

<div class="table-responsive">
    <table class="table table-hover align-middle">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id == CurrentSessionId)
                        {
                            <span class="badge bg-success">Current</span>
                        }
                        else if (_confirmingId == session.Id)
                        {
                            <div class="d-flex gap-1">
                                <button class="btn btn-danger btn-sm" @onclick="() => ConfirmRevokeAsync(session.Id)">
                                    Confirm
                                </button>
                                <button class="btn btn-outline-secondary btn-sm" @onclick="CancelConfirm">
                                    Cancel
                                </button>
                            </div>
                        }
                        else
                        {
                            <button class="btn btn-outline-danger btn-sm"
                                    @onclick="() => _confirmingId = session.Id">
                                Revoke
                            </button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingId;

    private void CancelConfirm() => _confirmingId = null;

    private async Task ConfirmRevokeAsync(string sessionId)
    {
        _confirmingId = null;
        await OnRevoke.InvokeAsync(sessionId);
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

