@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings
@using sv_e6d10935b0844757af832ef3520809a2.Services

<div class="p-4">
    <h4 class="mb-4">Security Settings</h4>

    @if (_security is null)
    {
        <p>Loading...</p>
        return;
    }

    <ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />

    <div class="card mb-3">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="mt-1">
                    @if (_twoFactorEnabled)
                    {
                        <span class="badge bg-success">Enabled</span>
                    }
                    else
                    {
                        <span class="badge bg-secondary">Disabled</span>
                    }
                </div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="twoFactor"
                       checked="@_twoFactorEnabled"
                       @onchange="e => _twoFactorEnabled = (bool)e.Value!" />
            </div>
        </div>
    </div>

    @if (_security.LastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-4">
            Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    <h5 class="mb-3">Active Sessions</h5>
    <ActiveSessionsTable Sessions="_security.Sessions" OnRevoke="HandleRevokeAsync" />
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? _security;
    private bool _twoFactorEnabled;

    protected override async Task OnInitializedAsync()
    {
        _security = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _security.TwoFactorEnabled;
    }

    private async Task HandleChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task HandleRevokeAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }
}

@namespace sv_e6d10935b0844757af832ef3520809a2.Components.Settings
@using sv_e6d10935b0844757af832ef3520809a2.Services

<div class="p-4">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_settings is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <label class="form-label fw-bold">Theme</label>
                <div>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="mb-4">
                <label class="form-label fw-bold">Font Size</label>
                <div>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>
            </div>

            <div class="mb-4">
                <label class="form-label fw-bold" for="language">Language</label>
                <select class="form-select" id="language" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)e.Value!" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            @if (_showSuccess)
            {
                <div class="alert alert-success alert-dismissible fade show py-2" role="alert">
                    Appearance saved!
                    <button type="button" class="btn-close" @onclick="() => _showSuccess = false"></button>
                </div>
            }

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <label class="form-label fw-bold">Live Preview</label>
            <div class="appearance-preview @PreviewThemeClass" style="@PreviewStyle">
                <div class="preview-header">
                    <strong>Preview</strong>
                </div>
                <div class="preview-body" style="@(_compactMode ? "padding:0.5rem;" : "padding:1rem;")">
                    <p style="margin-bottom:@(_compactMode ? "0.25rem" : "0.75rem")">
                        This is how your content will look with the selected settings.
                    </p>
                    <p style="margin-bottom:@(_compactMode ? "0.25rem" : "0.75rem")">
                        Theme: <strong>@_theme</strong> · Font: <strong>@_fontSize</strong> · Language: <strong>@_language</strong>
                    </p>
                    <button class="btn btn-sm btn-primary">Sample Button</button>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;
    [Parameter] public EventCallback OnSaved { get; set; }

    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private bool _showSuccess;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
